#include <iostream>
#include <vector>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    // dp[j] = number of ways to partition j into distinct positive integers
    // We'll use the classic DP: dp[0] = 1
    // For each i from 1..n, for j from n down to i: dp[j] += dp[j-i]
    vector<long long> dp(n + 1, 0);
    dp[0] = 1;

    for (int i = 1; i <= n; i++) {
        for (int j = n; j >= i; j--) {
            dp[j] += dp[j - i];
        }
    }

    cout << dp[n] << "\n";

    return 0;
}
